import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => {
  return (
    <nav style={{ padding: '1rem', background: '#f8f9fa', display: 'flex', justifyContent: 'space-between' }}>
      <Link to="/" style={{ fontWeight: 'bold', textDecoration: 'none', color: 'orange' }}>BAKESTORE</Link>
      <div>
        <Link to="/" style={{ margin: '0 10px' }}>Katalog</Link>
        <Link to="/keranjang">Keranjang 🛒</Link>
        <Link to="/login" style={{ margin: '0 10px' }}>Login</Link>
      </div>
    </nav>
  );
};

export default Navbar;
